#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,V=1e5;

struct Node{
    int lc,rc;
    int mx,mxt;
}t[N*80];

int n,m,tot,root[N],dep[N],f[N][17],ans[N];
vector<int> g[N];

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int y:g[x])
        if(y!=fa){
            f[y][0]=x;
            for(int i=1;f[f[y][i-1]][i-1];i++)
                f[y][i]=f[f[y][i-1]][i-1];
            dfs(y,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

void modify(int p,int l,int r,int x,int k){
    if(l==r){
        t[p].mx+=k;
        t[p].mxt=l;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid){
        if(!t[p].lc)
            t[p].lc=++tot;
        modify(t[p].lc,l,mid,x,k);
    }else{
        if(!t[p].rc)
            t[p].rc=++tot;
        modify(t[p].rc,mid+1,r,x,k);
    }
    t[p].mx=max(t[t[p].lc].mx,t[t[p].rc].mx);
    t[p].mxt=(t[p].mx==t[t[p].lc].mx?t[t[p].lc].mxt:t[t[p].rc].mxt);
}

int Merge(int p,int q,int l,int r){
    if(!p) return q;
    if(!q) return p;
    if(l==r){
        t[p].mx+=t[q].mx;
        t[p].mxt=l;
        return p;
    }
    int mid=l+r>>1;
    t[p].lc=Merge(t[p].lc,t[q].lc,l,mid);
    t[p].rc=Merge(t[p].rc,t[q].rc,mid+1,r);
    t[p].mx=max(t[t[p].lc].mx,t[t[p].rc].mx);
    t[p].mxt=(t[p].mx==t[t[p].lc].mx?t[t[p].lc].mxt:t[t[p].rc].mxt);
    return p;
}

void dfs2(int x,int fa){
    for(int y:g[x])
        if(y!=fa){
            dfs2(y,x);
            Merge(root[x],root[y],0,V);
        }
    ans[x]=t[root[x]].mxt;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    for(int i=1;i<=n;i++)
        root[i]=++tot;
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        int lca=LCA(u,v);
        modify(root[u],0,V,w,1);
        modify(root[v],0,V,w,1);
        modify(root[lca],0,V,w,-1);
        if(f[lca][0])
            modify(root[f[lca][0]],0,V,w,-1);
    }
    dfs2(1,0);
    for(int i=1;i<=n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
